class Solution:
    def countSubarrays(self, nums, k):
        n = len(nums)
        count = 0
        for i in range(n):
            for j in range(i, n):
                window = sorted(nums[i:j + 1])
                median = window[(len(window) - 1) // 2]
                if median == k:
                    count += 1
        return count

