var countSubarrays = function(nums, k) {
    const n = nums.length;
    const pos = nums.indexOf(k);
    const balanceCount = new Map([[0, 1]]);
    let balance = 0;
    for (let i = pos + 1; i < n; i++) {
        balance += nums[i] > k ? 1 : -1;
        balanceCount.set(balance, (balanceCount.get(balance) || 0) + 1);
    }
    let result = 0;
    balance = 0;
    for (let i = pos; i >= 0; i--) {
        if (i !== pos) {
            balance += nums[i] > k ? 1 : -1;
        }
        result += balanceCount.get(-balance) || 0;
        result += balanceCount.get(1 - balance) || 0;
    }
    return result;
};
